```
    @every(minutes=30)
    def on_start(self):
        for page in range(1, 500 + 1):
            url = 'data:, on_task-%s' % page
            self.crawl(url, callback=self.on_task, save=page)
        
    @config(priority=0)
    def on_task(self, response):
        page = response.save
        # 1W urls
        query = DB.load_urls(page, self.PAGE_SIZE)
        for url in query:
            self.crawl(url, callback=self.save_result, retries=4, timeout=20)

    @config(priority=1, age=7 * 24 * 60 * 60)
    def save_result(self, response):
        return json.loads(response.text)
```
