This is coming from the check performed at [this line](https://github.com/lorenzofox3/Smart-Table/blob/master/src/stPipe.js#L14), in this case even by defining the `scope.callServer ` within the link function of the `tableList` directive won't help, in fact the isolate scope var `scope.stPipe` will always be undefined, by inspecting the scope object I found that the my `callServer` function was defined in the $parent scope!

This led me to the (dirty) solution. That is, I've redefined the `tableList` body to have everyghing within the pre-link function and set the `replace: false,`:

```
angular.module('app')
.directive('tableList', function() {
    return {
        restrict: 'E',
        replace: false,
        templateUrl: '/core/components/table/table-list.tpl.html', // same template as above
        link: {
            pre: function(scope, elem, attrs) {
                scope.theads = attrs.schema.properties;
                scope.callServer = function callServer(tableState, tableCtrl) {
                    scope.isLoading = true;
                    var params = {};
                    // .. fill params obj with tableState fields..
                    // async fn returning a promise
                    makeCall(params)
                        .then(function (items) {
                            scope.displayedCollection = items;
                            // .. set pagination and other things
                            scope.isLoading = false;
                        })
                }
            }
        }
    }
});
```
Even if this work I create an extra unnecessary dom element (because replace is false), I wish there was a cleaner solution

